SELECT customer_id AS customerId, COUNT(*) AS orderCount, COALESCE(SUM(total_amount), 0) AS totalAmount FROM oms_sales_order WHERE enterprise_id = #{enterpriseId} AND customer_id IN
#{id}
GROUP BY customer_id

SELECT COALESCE(SUM(total_amount), 0) AS totalSales,
       COALESCE(SUM(total_profit), 0) AS totalProfit,
       COUNT(*) AS orderCount
FROM oms_sales_order
WHERE enterprise_id = #{enterpriseId}
  AND status != 'CANCELLED'
  AND created_at >= #{startDate}
  AND created_at <= #{endDate}

SELECT id, order_no AS orderNo, total_amount AS totalAmount,
       status, payment_status AS paymentStatus, created_at AS createdAt
FROM oms_sales_order
WHERE enterprise_id = #{enterpriseId}
  AND customer_id = #{customerId}
ORDER BY id DESC
LIMIT #{limit}

SELECT DISTINCT enterprise_id
FROM oms_sales_order
WHERE status != 'CANCELLED'
  AND created_at >= #{startDate}
  AND created_at <= #{endDate}
